  ('cpa-moex-00335', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列對於股份有限公司發起人之敘述，何者錯誤？', '["發起人之股份非於公司設立登記一年後，不得轉讓", "發起人對於公司在設立登記前所負債務，在登記後亦負連帶責任", "應有二人以上為發起人，但政府或法人股東一人所組織之股份有限公司，不受上述人數之限制", "未認足之第一次發行股份，及已認而未繳股款者，應由發起人連帶認繳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00336', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公開發行股票公司，其董事在任期中轉讓超過選任當時所持有之公司股份數額二分之一時，下列 敘述何者正確？', '["轉讓股份之行為，違反法律禁止規定而無效", "二分之一係採單次交易計算", "董事在任期中其股份有增減時，應向主管機關申報並公告之", "該董事由股東會特別決議解任之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00337', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '非公開發行之股份有限公司，下列何種議案得於股東會中以臨時動議提出？', '["董事競業許可", "盈餘轉增資", "將已發行之票面金額股全數轉換為無票面金額股", "公積轉增資"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00338', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何種公司，其股東會必須採書面方式行使表決權？', '["上市（櫃）公司", "非公開發行公司", "公開發行公司", "公司法並未強制股份有限公司採行此制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00339', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司為一公開發行公司，該公司章程中明確採取候選人提名制度，公司派提名現有董 事九人，市場派欲提名甲、乙、丙三人競選該公司董事，下列敘述何者錯誤？', '["市場派須為持有A公司已發行股份總數百分之一股份之股東，並以書面向公司提出董事候選人 名單", "A公司應於股東會召開前之停止股票過戶日前，訂十日以上之期間公告受理股東為董事候選人 提名", "市場派提名股東參選時，應敘明被提名人甲、乙、丙三人之重要學經歷，並檢附相關證明文件", "A公司的董事長丁擔心甲、乙、丙當選，故意不將甲、乙、丙三人列入董事候選人名單，證券 主管機關得對丁處新臺幣二十四萬元以上二百四十萬元以下罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00340', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司（下稱A公司）擬與其董事甲之配偶乙交易土地一筆。A公司董事會討論該土地 交易案時，下列敘述何者正確？', '["甲不得出席該次董事會", "甲不得就該土地交易案行使表決權", "甲經說明利害關係後，始得就該土地交易案行使表決權", "乙對董事會應負說明義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00341', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司（下稱A公司）之法人股東B指派甲為其代表人當選A公司董事，甲再被推選 為董事長。但因B事後不滿甲之表現，遂改派乙為其法人代表。下列敘述何者正確？', '["A公司須重新選出新任董事長", "甲董事長身分未因被撤換而改變", "乙當然繼任為A公司董事長", "何人擔任A公司董事長應由B決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00342', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司持有B公司已發行有表決權股份總數50%，並控制C公司業務經營；A公司有9席董事， D公司有5席董事，其中4名董事與A公司之董事相同。A公司持有E公司25%有表決權股份； B、C、D三家公司分別持有E公司10%有表決權股份。依現行公司法，下列何者為A公司之從 屬公司？', '["B公司", "C公司", "D公司", "E公司"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00343', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依公司法規定，下列何者不是A股份有限公司（下稱A公司）董事長甲之職權範圍？', '["擔任董事會之召集權人", "擔任股東會之主席", "A公司對外簽約之公司代表人", "A公司與董事乙簽訂買賣契約時之公司代表人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00344', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司（下稱A公司）公開發行新股，順利完成增資後，股價立即暴跌，受損害之投資人欲 援引證券交易法（下稱本法）公開說明書不實之規定請求賠償，下列何者非屬本法第32條明定可 求償之對象？', '["A公司", "A公司負責人", "未在公開說明書上簽章之公司職員", "未在公開說明書上簽章之A公司該發行案證券承銷商"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00345', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公開發行股票之A公司，經代表已發行股份總數三分之二以上股東之出席，出席股東表決權過半 數之同意而進行股票之私募，應募之人均為銀行業或保險業者，共計40家業者應募，A公司於股 款收畢後第7日報請主管機關備查。依證券交易法之規定，關於A公司私募股票之程序，下列敘 述何者錯誤？', '["A公司本件私募案之應募人數超額", "A公司本件私募案之股東會決議門檻，不符證券交易法規定", "雖A公司非上市櫃公司，仍可辦理私募", "A公司本件私募案毋須事先向主管機關申報"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00346', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '股票上櫃之A股份有限公司（下稱A公司）章程設五席董事，某日，董事甲與董事乙於出差洽公 途中因交通事故不幸同時身亡，A公司如何填補董事空缺？', '["於最近一次股東會補選", "於出缺事實發生之日起三十日內，召集董事會決議補選日期", "於出缺事實發生之日起六十日內，召開股東臨時會補選", "A公司仍有三席董事，不必補選"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00347', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司為一家從事貨櫃運輸的上市公司。最近A公司剛向主管機關申報第一季財務報告，由於該 公司營運不佳，導致該公司之董事長與總經理皆發生變動。依證券交易法之規定，下列敘述何者 正確？', '["A公司第一季財務報告應於每會計年度終了後三個月內，公告並向主管機關申報", "A公司所公告申報之第一季財務報告應經會計師查核簽證、董事會通過及監察人承認", "A公司董事長與總經理發生變動，應於事實發生之日起二日內公告並向主管機關申報", "A公司董事長與總經理發生變動，應於事實發生之日起三日內公告並向主管機關申報"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00348', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依證券交易法規定，除經主管機關核准外，公開發行公司最晚應於每會計年度終了後多久內，向 主管機關申報內部控制聲明書？', '["10日內", "45日內", "2個月內", "3個月內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
